# =============================================================================
# MAIN SCRIPT
# =============================================================================

PRODUCTS = {
    "evermusic": EVERMUSIC,
    "flacbox": FLACBOX,
    "evervideo": EVERVIDEO,
    "evertag": EVERTAG,
}


def build_prose_block(text):
    return f'<div class="hx:sr-only">\n\n{text}\n\n</div>\n'


def process_file(product, lang, text):
    filename = f"_index.{lang}.md"
    filepath = os.path.join(BASE_DIR, product, filename)

    if not os.path.exists(filepath):
        print(f"  SKIP (not found): {filepath}")
        return False

    with open(filepath, "r", encoding="utf-8") as f:
        content = f.read()

    if "hx:sr-only" in content:
        print(f"  SKIP (already has prose): {filepath}")
        return False

    # Find the closing --- of frontmatter (second occurrence)
    # The frontmatter starts and ends with ---
    first_dash = content.index("---")
    second_dash = content.index("---", first_dash + 3)
    frontmatter_end = second_dash + 3  # position right after the closing ---

    before = content[:frontmatter_end]
    after = content[frontmatter_end:]

    prose = build_prose_block(text)

    # Insert: frontmatter + newline + prose block + rest of content
    new_content = before + "\n\n" + prose + after

    with open(filepath, "w", encoding="utf-8") as f:
        f.write(new_content)

    print(f"  DONE: {filepath}")
    return True


def main():
    total = 0
    done = 0
    skipped = 0

    for product, translations in PRODUCTS.items():
        print(f"\n=== {product.upper()} ===")
        for lang in LANGUAGES:
            total += 1
            if lang not in translations:
                print(f"  MISSING translation: {product}/{lang}")
                skipped += 1
                continue
            if process_file(product, lang, translations[lang]):
                done += 1
            else:
                skipped += 1

    print(f"\n{'='*50}")
    print(f"Total files: {total}")
    print(f"Processed:   {done}")
    print(f"Skipped:     {skipped}")


if __name__ == "__main__":
    main()
